mapper.select:
SELECT m.manager_id, m.manager_name, m.company_id, c.company_name, m.start_work_date, m.experience_years, m.manage_scale, m.current_fund_count, COUNT(DISTINCT r.fund_id) AS imported_fund_count FROM fund_manager m LEFT JOIN fund_company c ON c.company_id = m.company_id LEFT JOIN fund_manager_relation r ON r.manager_id = m.manager_id AND r.is_current = 1
AND m.manager_name LIKE CONCAT('%', #{query.keyword}, '%')
AND m.company_id = #{query.companyId}
AND EXISTS ( SELECT 1 FROM manager_tag_relation mtr WHERE mtr.manager_id = m.manager_id AND mtr.tag_id IN
#{tagId}
)
GROUP BY m.manager_id, m.manager_name, m.company_id, c.company_name, m.start_work_date, m.experience_years, m.manage_scale, m.current_fund_count ORDER BY imported_fund_count DESC, m.manager_id DESC
